 def __init__(s):s.p=json.loads(lzma.decompress(base64.b85decode(s.P)).decode())
 def run(s,x):
  c=s.g(x.traderData);o={};q=defaultdict(int);r=dict(x.position);u=s.m(x.order_depths.get(s.U));s.c(x,c,r,q,o)
  for p in s.T:
   d=x.order_depths.get(p)
   if d is None:continue
   a=s.a(p,d,u)
   if a is None:continue
   y=s.p.get(p,{}).get(a['k'])
   if y is None or y[1]<s.R.get(p,.75):continue
   z=int(y[0])
   if z==0:continue
   if z>0:
    n=min(a['av'],s.L[p]-r.get(p,0)-q[p])
    if n>0:s.o(o,q,p,a['ap'],n);s.e(c,p,x.timestamp+s.H*100,1,n)
   else:
    n=min(a['bv'],r.get(p,0)+s.L[p]+q[p])
    if n>0:s.o(o,q,p,a['bp'],-n);s.e(c,p,x.timestamp+s.H*100,-1,n)
  return o,0,json.dumps(c,separators=(',',':'))
 def g(s,t):
  if not t:return {'open_trades':{}}
  try:c=json.loads(t)
  except json.JSONDecodeError:return {'open_trades':{}}
  c.setdefault('open_trades',{});return c
 def a(s,p,d,u):
  b=sorted(d.buy_orders.items(),key=lambda i:i[0],reverse=True);v=sorted(d.sell_orders.items(),key=lambda i:i[0])
  if not b or not v:return None
  bp,bq=b[0];ap,aq=v[0]
  if p.startswith('VEV_'):
   if u is None:return None
   w=int(round((u-float(p.split('_')[1]))/s.M))
  else:w=0
  return {'k':f'{int(bp)}|{int(ap)}|{int(abs(bq))}|{int(abs(aq))}|{w}','bp':int(bp),'ap':int(ap),'bv':int(abs(bq)),'av':int(abs(aq))}
 def m(s,d):
  if d is None or not d.buy_orders or not d.sell_orders:return None
  return (max(d.buy_orders)+min(d.sell_orders))/2.0
 def c(s,x,c,r,q,o):
  h=c.get('open_trades',{})
  for p in list(h.keys()):
   d=x.order_depths.get(p)
   if d is None or not d.buy_orders or not d.sell_orders:continue
   w=[];bb=max(d.buy_orders);ba=min(d.sell_orders)
   for t,z,n in h[p]:
    if t>x.timestamp:w.append([t,z,n]);continue
    if z>0:s.o(o,q,p,int(bb),-int(n))
    else:s.o(o,q,p,int(ba),int(n))
   if w:h[p]=w
   else:del h[p]
 def e(s,c,p,t,z,n):c.setdefault('open_trades',{});c['open_trades'].setdefault(p,[]).append([int(t),int(z),int(n)])
 def o(s,o,q,p,x,n):
  if n==0:return
  o.setdefault(p,[]).append(Order(p,int(x),int(n)));q[p]+=int(n)
